import React, { useState, useEffect } from "react";
import { Link, Outlet, useNavigate, useLocation } from "react-router-dom";
import {
  Home,
  Users,
  List,
  BarChart2,
  DollarSign,
  LogOut,
  Menu,
  X,
} from "react-feather";

export default function AdminLayout() {
  const navigate = useNavigate();
  const location = useLocation();
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);

  // ✅ Detect screen resize dynamically
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
      if (window.innerWidth > 768) setIsSidebarOpen(true); // Always open on desktop
      else setIsSidebarOpen(false); // Hidden by default on mobile
    };
    window.addEventListener("resize", handleResize);
    handleResize();
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const logout = () => {
    localStorage.clear();
    navigate("/login", { replace: true });
  };

  // ✅ Auto-close sidebar when clicking link (only on mobile)
  const handleNavClick = () => {
    if (isMobile) setIsSidebarOpen(false);
  };

  return (
    <div
      style={{
        display: "flex",
        minHeight: "100vh",
        backgroundColor: "#f6f9fc",
        overflowX: "hidden",
      }}
    >
      {/* 🔹 Overlay for mobile */}
      {isMobile && isSidebarOpen && (
        <div
          onClick={() => setIsSidebarOpen(false)}
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            width: "100vw",
            height: "100vh",
            background: "rgba(0,0,0,0.4)",
            zIndex: 9,
          }}
        ></div>
      )}

      {/* 🔹 Sidebar */}
      <aside
        style={{
          width: 240,
          background: "#13385a",
          color: "#fff",
          padding: "24px",
          position: isMobile ? "fixed" : "sticky",
          top: 0,
          left: isMobile
            ? isSidebarOpen
              ? 0
              : "-260px"
            : 0,
          height: "100vh",
          zIndex: 10,
          overflowY: "auto",
          transition: "left 0.3s ease-in-out",
        }}
      >
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <h4 style={{ margin: 0, fontSize: "1.2rem" }}>Broker Admin</h4>
          {isMobile && (
            <button
              onClick={() => setIsSidebarOpen(false)}
              style={{
                background: "transparent",
                border: "none",
                color: "#fff",
                cursor: "pointer",
              }}
            >
              <X size={24} />
            </button>
          )}
        </div>

        <ul style={{ listStyle: "none", marginTop: 30, padding: 0 }}>
          {[
            { to: "/admin", label: "Dashboard", icon: <Home size={18} /> },
            { to: "/admin/users", label: "Users", icon: <Users size={18} /> },
            {
              to: "/admin/CategoryManager",
              label: "Category List",
              icon: <List size={18} />,
            },
            {
              to: "/admin/priceanalytics",
              label: "Analytics",
              icon: <BarChart2 size={18} />,
            },
            {
              to: "/admin/pricelist",
              label: "Price List",
              icon: <DollarSign size={18} />,
            },
          ].map((item) => (
            <li key={item.to} style={styles.navItem}>
              <Link
                to={item.to}
                style={{
                  ...styles.link,
                  background:
                    location.pathname === item.to ? "#0f2942" : "transparent",
                }}
                onClick={handleNavClick}
              >
                {item.icon}
                {item.label}
              </Link>
            </li>
          ))}
        </ul>

        <button
          onClick={logout}
          style={{
            background: "#e74c3c",
            border: "none",
            padding: "10px 14px",
            color: "#fff",
            borderRadius: 6,
            marginTop: 20,
            cursor: "pointer",
            width: "100%",
            fontWeight: 500,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            gap: 6,
          }}
        >
          <LogOut size={18} /> Logout
        </button>
      </aside>

      {/* 🔹 Main Content */}
      <main
        style={{
          flex: 1,
          marginLeft: !isMobile ? 240 : 0,
          width: "100%",
          transition: "margin 0.3s ease",
          position: "relative",
          zIndex: 1,
        }}
      >
        {/* Top Bar */}
        <div
          style={{
            background: "#fff",
            padding: "12px 20px",
            boxShadow: "0 1px 4px rgba(0,0,0,0.1)",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            position: "sticky",
            top: 0,
            zIndex: 8,
          }}
        >
          {isMobile && (
            <button
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              style={{
                background: "transparent",
                border: "none",
                cursor: "pointer",
                color: "#13385a",
              }}
            >
              {isSidebarOpen ? <X size={26} /> : <Menu size={26} />}
            </button>
          )}
          <h3 style={{ margin: 0, color: "#13385a", fontWeight: 600 }}>
            Admin Dashboard
          </h3>
          <div></div>
        </div>

        {/* Page Content */}
        <div style={{ padding: "24px" }}>
          <Outlet />
        </div>
      </main>

      {/* ✅ Extra responsive CSS */}
      <style>
        {`
          a:hover {
            background: #0b2947 !important;
          }

          @media (max-width: 768px) {
            aside {
              box-shadow: 2px 0 8px rgba(0,0,0,0.15);
            }

            main {
              margin-left: 0 !important;
              width: 100%;
            }
          }
        `}
      </style>
    </div>
  );
}

const styles = {
  navItem: {
    padding: "8px 0",
  },
  link: {
    display: "flex",
    alignItems: "center",
    gap: 10,
    color: "#fff",
    textDecoration: "none",
    fontSize: 15,
    fontWeight: 500,
    padding: "8px 10px",
    borderRadius: "8px",
    transition: "background 0.2s",
  },
};
